mapper.select:
SELECT gr.id, #{userId} AS user_id, GROUP_CONCAT(DISTINCT CASE WHEN u.id != #{userId} THEN u.nickname END ORDER BY rp.seat_index) AS opponent_names, CASE WHEN gr.winner_id = #{userId} THEN 1 ELSE 0 END AS result, gr.score, gr.create_time AS game_time, NULL AS duration FROM game_record gr JOIN room r ON gr.room_id = r.id JOIN room_player rp ON rp.room_id = r.id JOIN `user` u ON u.id = rp.user_id WHERE EXISTS ( SELECT 1 FROM room_player rp2 WHERE rp2.room_id = gr.room_id AND rp2.user_id = #{userId} )
AND gr.create_time >= #{startTime}
AND gr.create_time <= #{endTime}
GROUP BY gr.id ORDER BY gr.create_time DESC
